var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"퇴근길. 도로는 어김없이 기름진 전조등 불빛에 꽉 막혔다.","JPN":"退勤後の帰り道。道路は今日もギラギラしたヘッドライトの輝きで埋め尽くされている。","ENG":"Out of the office and going home. The streets are packed with flashing headlights again.","TWN":"下班路上，塞在大燈閃爍的車陣中。"},"stage":{"bg":"SKYLINE_NIGHT2","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"머릿속에는 샤워 후에 맥주 한 잔 마실 생각만 가득하다.","JPN":"頭の中にはシャワー後のビールのことでいっぱい。","ENG":"All I want to do is get home, take a shower, and drink a cold beer.","TWN":"滿腦子都是洗澡後要來杯冰涼的啤酒。"},"stage":{"bg":"SKYLINE_NIGHT2","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"당장 떠올릴 수 있는 인생의 낙이 고작 그것뿐인 현실도 이제 익숙해졌다.","JPN":"今すぐ思い浮かぶ人生の楽しみがそれだけ、という現実にももう慣れた。","ENG":"I've accepted that this is my reality, and the small enjoyment I can get out of it.","TWN":"已經習慣現在人生中最快樂的事僅此而已。"},"stage":{"bg":"SKYLINE_NIGHT2","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"이 도시에 취직한 이후로 친구들과 연락을 안 한 지도 오래됐다.","JPN":"この街で就職してから、最後に友達と連絡を取り合ったのはいつだったか。","ENG":"I have become more distant with my friends after getting a job in the city.","TWN":"自從來到這座城市上班後，連朋友都已經許久未聯繫。"},"stage":{"bg":"SKYLINE_NIGHT2","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"문득, 올려다본 하늘에 시커먼 그림자가 구름을 헤치고 나아간다. 차원 함선이다.","JPN":"ふと見上げた空には真っ黒な影が雲をかき分けながら進んでいく。次元艦船だ。","ENG":"As I look at the sky above, I see a shadow soaring through the clouds. A dimensional ship.","TWN":"突然抬頭一看，天空中一個黑壓壓的影子劃開雲朵而過，原來是次元艦船。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"용병이 된다던 녀석은 잘 지낼까.\\n시선을 앞차 꽁무니로 돌릴 즈음이었다.","JPN":"傭兵になると言っていたあいつはどうしているだろう。\\n前の車に視線を向けた頃だった。","ENG":"[[","TWN":"成為傭兵的傢伙過得好嗎？\\n視線回到前車車尾。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"사람 엄청 많다!","JPN":"人がいっぱいだね！","ENG":"Look at all those people!","TWN":"好多人喔！"},"stage":{"bg":"COLOSSEUM","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"여긴 대체 어디야? 우린 분명 방금 전까지 놀이동산에 있었는데?","JPN":"ここはいったいどこなんだよ？　さっきまで確かに遊園地にいたのに！","ENG":"Where are we? Weren't we in an amusement park just before?","TWN":"這裡到底是哪裡？我們剛才不是還在遊樂園嗎？"},"stage":{"bg":"COLOSSEUM","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"글쎄? 루트가 말한 디 엔드 랜드 아닐까?","JPN":"さあ？　ルートが言ってたジ・エンドランドじゃないかな？","ENG":"I dunno. Maybe this is that The End Land that Root talked about?","TWN":"這個嘛，是路特說的終點站樂園嗎？"},"stage":{"bg":"COLOSSEUM","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"디 엔드 랜드라면…… 분명 투기장이었지.","JPN":"ジ・エンドランドっていうと……確か闘技場だったな。","ENG":"The End Land should be… the colosseum.","TWN":"終點站樂園……不是競技場嗎？"},"stage":{"bg":"COLOSSEUM","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"도로시, 저기 봐!","JPN":"ドロシー、あそこ見てよ！","ENG":"Dorothy! Look over there!","TWN":"桃樂絲，你看那裡！"},"stage":{"bg":"COLOSSEUM","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"저기? 저기 어디?","JPN":"あそこ？　どこ？","ENG":"Where? I can’t see.","TWN":"那裡？哪裡？"},"stage":{"bg":"COLOSSEUM","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"아이 참! 저쪽에! 수아야!","JPN":"ああ、もう！　あっち！　コトリだよ！","ENG":"Oh, come on! Over there! It's Skia!","TWN":"真是的！那裡啦！是蘇亞！"},"stage":{"bg":"COLOSSEUM","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"리온랑 글린다, 그리고 루루까지. 다들 밧줄에 묶여 있어.","JPN":"リオンとグリンダ、それにルルまで。みんな縄に縛られてる。","ENG":"Liona, Glinda, and Lulu as well! But they're all tied up.","TWN":"萊恩、格琳達和露露，她們全都被繩子綁著。"},"stage":{"bg":"COLOSSEUM","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"정말이잖아…… 게다가 눈에 안대까지 채웠어.","JPN":"本当だ……しかも目隠しまでされてる。","ENG":"You're right... They’ve been blindfolded, too!","TWN":"還真的……而且還戴著眼罩。"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"큰일이다. 해적은 포로로 붙잡히면 상어밥이 되는데.","JPN":"どうしよう。海賊は捕虜になるとサメのエサになっちゃうんだよ。","ENG":"This is bad. Once a pirate is captured they become shark food!","TWN":"糟糕！海盜變成俘虜的話，會被扔到海裡餵鯊魚欸！"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};